{
  "premium_report": {
    "report_title": "프리미엄 사주 스토리",
    "version": "1.0",
    "sections": [
      {
        "section_id": "overall_1",
        "category": "overall",
        "title": "프리미엄 사주 스토리",
        "headline": "조용하지만 다정하게 흐르는 관계의 리듬",
        "summary_lines": [
          "관계 속에서 실무를 차근차근 챙깁니다.",
          "의사결정은 맥락 살피기와 우선순위 정렬이 핵심입니다.",
          "새로운 환경에서도 협업과 실행으로 신뢰를 쌓아갑니다."
        ],
        "core_insight": "사람 다루는 흐름은 말보다 실제 관계의 맥락으로 상황을 풀어가는 편입니다. 처음 보이는 인상과 판단 기준이 다를 수 있어 중요한 결정을 내리기 전에 주변 관계를 먼저 살피는 습관이 도움이 됩니다. 같은 상황에서도 선택 순서를 조정하는 편이라 결과가 상황에 따라 다르게 나타날 수 있습니다. 차분하고 실용적인 흐름이 강점이지만 속도를 조금 더 앞당기면 더 큰 성과를 얻을 수 있습니다. 또 새로운 환경에선 적응력이 좋아 협업이 원활하고, 꾸준한 실행으로 신뢰를 쌓아갑니다. 의사결정 흐름이 느려질 수 있어 목표를 작은 단계로 나누고 우선순위를 분명히 하는 것이 좋습니다.",
        "strength": "관계의 맥락을 먼저 살피고 차분하게 실행하는 능력이 실제 성과로 잘 이어집니다.",
        "risk": "의사결정 속도가 느려지면 기회가 빨리 지나갈 수 있어 상황에 따라 조정이 필요합니다.",
        "action_points": [
          "매일 작은 목표를 3가지로 나누고 우선순위를 매기는 습관을 들인다.",
          "관계 상황에서 먼저 경청하고 핵심 맥락을 파악하는 데 초점을 맞춘다.",
          "새로운 환경에서의 협업 시 초기 온보딩을 2주 단위로 점검한다."
        ],
        "action_note": "일상 속 작은 습관 변화가 큰 흐름을 만듭니다. 꾸준히 실행하면서 주변과의 신뢰를 차곡차곡 쌓아가세요."
      }
    ]
  }
}
